import React, { useState, useEffect, useRef } from 'react'; // Importa useState, useEffect, y useRef

const skills = [
  { name: 'WordPress', level: 100 },
  { name: 'Woocommerce', level: 100 },
  { name: 'Elementor', level: 95 },
  { name: 'Divi', level: 95 },
  { name: 'WP-Bakery', level: 85 },
  { name: 'LearnDash', level: 90 },
  { name: 'Yoast SEO', level: 95 },
  { name: 'Shopify', level: 95 },
  { name: 'Prestashop', level: 85 },
  { name: 'Webflow', level: 90 },
  { name: 'Magento', level: 80 },
  { name: 'Drupal', level: 80 },
  { name: 'HTML5', level: 100 },
  { name: 'CSS3', level: 95 },
  { name: 'JavaScript', level: 90 },
  { name: 'ECMAScript', level: 90 },
  { name: 'PHP 8.1', level: 88 },
  { name: 'MySQL', level: 85 },
  { name: 'Bootstrap', level: 92 },
  { name: 'React.js', level: 80 },
  { name: 'Angular.js', level: 75 },
  { name: 'Vue.js', level: 85 },
  { name: 'Three.js', level: 70 },
  { name: 'Laravel', level: 70 },
  { name: 'Liferay', level: 79 },
  { name: 'Adobe Photoshop', level: 50 },
  { name: 'Adobe Illustrator', level: 50 },
  { name: 'Figma', level: 88 },
  { name: 'Google ADS', level: 75 },
  { name: 'Google Analytics', level: 82 },
  { name: 'Git', level: 90 },
  { name: 'Google Tag Manager', level: 78 },
  { name: 'SEO orgánico', level: 88 },
  { name: 'Gestión de Hosting', level: 85 },
  { name: 'Gestión de dominio', level: 90 }
];

const SkillsSection = () => {
  // Estado para controlar la animación de entrada de los elementos de la sección
  const [animateSectionIn, setAnimateSectionIn] = useState(false);
  // Estado para controlar la animación de las barras de progreso
  const [animateBars, setAnimateBars] = useState(false);

  // Refs para observar los elementos
  const headerRef = useRef(null); // Para el título y la descripción
  const skillsGridRef = useRef(null); // Para el contenedor de la cuadrícula de habilidades

  // useEffect para el IntersectionObserver
  useEffect(() => {
    const observerOptions = {
      root: null, // El viewport es el elemento raíz
      rootMargin: '0px',
      threshold: 0.1 // Activar cuando el 10% del elemento sea visible
    };

    // Observador para el encabezado de la sección
    const headerObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          setAnimateSectionIn(true); // Activa la animación general de la sección
          // console.log('Skills Header visible, animating section in!'); // Para depuración
          headerObserver.unobserve(entry.target); // Dejar de observar una vez que se hizo visible
        }
      });
    }, observerOptions);

    // Observador para las barras de progreso (se activan un poco después o al mismo tiempo)
    const skillsGridObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          setAnimateBars(true); // Activa la animación de las barras
          // console.log('Skills Grid visible, animating bars!'); // Para depuración
          skillsGridObserver.unobserve(entry.target);
        }
      });
    }, observerOptions);

    // Adjuntar observadores a los elementos
    if (headerRef.current) headerObserver.observe(headerRef.current);
    if (skillsGridRef.current) skillsGridObserver.observe(skillsGridRef.current);

    // Función de limpieza para desconectar los observadores
    return () => {
      if (headerRef.current) headerObserver.unobserve(headerRef.current);
      if (skillsGridRef.current) skillsGridObserver.unobserve(skillsGridRef.current);
      headerObserver.disconnect();
      skillsGridObserver.disconnect();
    };
  }, []); // Se ejecuta solo una vez al montar el componente

  return (
    <section id="skills" className="py-20 bg-white">
      <div className="container mx-auto px-6">
        {/* Encabezado de la sección de habilidades */}
        <div 
          ref={headerRef} // Adjunta la ref
          className={`text-center mb-16 transition-all duration-700 ease-out 
                      ${animateSectionIn ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`}
        >
          <h2 className="text-4xl font-bold text-gray-900 mb-4">
            Mis <span className="text-blue-600">Habilidades</span>
          </h2>
          <p className="text-xl text-gray-600 max-w-2xl mx-auto">
            Tecnologías y herramientas que domino y disfruto utilizando.
          </p>
        </div>

        {/* Contenedor de la cuadrícula de habilidades */}
        <div 
          ref={skillsGridRef} // Adjunta la ref
          className={`grid grid-cols-1 md:grid-cols-2 gap-6 max-w-4xl mx-auto
                      transition-all duration-700 ease-out delay-200 
                      ${animateSectionIn ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10'}`}
        >
          {skills.map((skill, index) => (
            <div 
              key={index} 
              className="bg-gray-50 rounded-xl p-4 hover:shadow-md transition-shadow"
              // Opcional: añadir un pequeño retraso a cada tarjeta para un efecto escalonado
              style={{ transitionDelay: animateSectionIn ? `${index * 50}ms` : '0ms' }}
            >
              <div className="flex justify-between mb-2">
                <span className="font-medium text-gray-800">{skill.name}</span>
                {/* Muestra el nivel final una vez que las barras se animan */}
                <span className="text-blue-600 font-medium">
                  {animateBars ? `${skill.level}%` : '0%'}
                </span>
              </div>
              <div className="relative h-2.5 bg-gray-200 rounded-full overflow-hidden">
                <div 
                  className="absolute top-0 left-0 h-full bg-gradient-to-r from-blue-400 to-blue-600 transition-transform duration-1000 ease-out"
                  style={{ 
                    transformOrigin: 'left', 
                    // Anima el `scaleX` solo cuando `animateBars` es true
                    transform: animateBars ? `scaleX(${skill.level / 100})` : `scaleX(0)` 
                  }}
                ></div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default SkillsSection;
